import React from "react";
import { graphql } from "gatsby";
import Layout from "../components/layout";
import Seo from "../components/seo";
import PostList from "../components/post-list";
import Pagination from "../components/pagination-new";
import CategoryButtons from "../components/category-buttons";

const CategoryTemplate = ({ data, pageContext }) => {
  const { category, currentPage, numPages } = pageContext;
  const posts = data.allMarkdownRemark.edges;
  const categories = ["All", ...data.categories.group.map(group => group.fieldValue)];
  const { siteUrl } = data.site.siteMetadata;
  const currentPath = typeof window !== "undefined" ? window.location.pathname : "";

  // Constructing the list of blog posts for structured data
  const itemListElement = posts.map(({ node }, index) => {
    const { date, slug } = node.frontmatter;
    const dateObj = new Date(date);
    const year = dateObj.getFullYear();
    const month = ('0' + (dateObj.getMonth() + 1)).slice(-2); // Ensure month is 2 digits
    const day = ('0' + dateObj.getDate()).slice(-2); // Ensure day is 2 digits

    return {
      "@type": "ListItem",
      "position": index + 1,
      "url": `${siteUrl}/${year}/${month}/${day}/${slug}`
    };
  });

  // Structured data for the category page
  const structuredData = {
    "@context": "http://schema.org",
    "@type": "ItemList",
    "name": `${category}`,
    "description": `A list of posts in the category ${category}.`,
    "url": `${siteUrl}${currentPath}`,
    "itemListElement": itemListElement
  };

  return (
    <>
      <Seo title={`Posts in ${category} - Page ${currentPage}`} />
      <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: JSON.stringify(structuredData) }}></script>
      <Layout>
        <div className="category-page">
          <div className="container">
            <h1>Posts in category: {category}</h1>
            <CategoryButtons categories={categories} />
            <PostList posts={posts} currentPath={currentPath} />
            <Pagination currentPage={currentPage} numberOfPages={numPages} basePath={`/category/${category}`} />
          </div>
        </div>
      </Layout>
    </>
  );
};

export const query = graphql`
  query($category: String!) {
    allMarkdownRemark(
      filter: {frontmatter: {category: {eq: $category}}}
      sort: {frontmatter: {date: DESC}}
    ) {
      edges {
        node {
          frontmatter {
            title
            date(formatString: "YYYY/MM/DD")
            slug
            excerpt
            category
            image {
              childImageSharp {
                gatsbyImageData(layout: FULL_WIDTH)
              }
            }
          }
          rawMarkdownBody
        }
      }
    }
    categories: allMarkdownRemark {
      group(field: {frontmatter: {category: SELECT}}) {
        fieldValue
      }
    }
    site {
      siteMetadata {
        siteUrl
      }
    }
  }
`;

export default CategoryTemplate;
